public class Arr {
  static int first(int[] a){ return a[0]; }
  static int len(int[] a){ return a.length; }
  static int at(int[] a, int i){ return a[i]; }
  static int[] make(int n){ return new int[n]; }
  static long firstL(long[] a){ return a[0]; }
  static void set(int[] a, int i, int v){ a[i] = v; }
}
